def min_operations_to_form_portal(test_cases):
    results = []

    for n, m, grid in test_cases:
        min_operations = float('inf')

        # Iterate over all possible top-left corners of sub-rectangles
        for top in range(n):
            for left in range(m):
                # Iterate over all possible bottom-right corners
                for bottom in range(top + 4, n):
                    for right in range(left + 3, m):
                        # Calculate the number of changes needed for this sub-rectangle
                        changes = 0

                        # Check the first and last rows (except corners)
                        for y in range(left + 1, right):
                            if grid[top][y] == '0':
                                changes += 1
                            if grid[bottom][y] == '0':
                                changes += 1

                        # Check the first and last columns (except corners)
                        for x in range(top + 1, bottom):
                            if grid[x][left] == '0':
                                changes += 1
                            if grid[x][right] == '0':
                                changes += 1

                        # Check the inner part of the sub-rectangle
                        for x in range(top + 1, bottom):
                            for y in range(left + 1, right):
                                if grid[x][y] == '1':
                                    changes += 1

                        # Update the minimum operations needed
                        min_operations = min(min_operations, changes)

        results.append(min_operations)

    return results

