def minimal_difference(t, test_cases):
    results = []
    for a, b, c in test_cases:
        total_duration = a * 1 + b * 2 + c * 3
        max_possible_sum = total_duration // 2

        dp = [False] * (max_possible_sum + 1)
        dp[0] = True

        for _ in range(a):
            for j in range(max_possible_sum, 0, -1):
                if j >= 1:
                    dp[j] = dp[j] or dp[j - 1]

        for _ in range(b):
            for j in range(max_possible_sum, 0, -1):
                if j >= 2:
                    dp[j] = dp[j] or dp[j - 2]

        for _ in range(c):
            for j in range(max_possible_sum, 0, -1):
                if j >= 3:
                    dp[j] = dp[j] or dp[j - 3]

        closest_sum = 0
        for j in range(max_possible_sum + 1):
            if dp[j]:
                closest_sum = j

        min_difference = abs(total_duration - 2 * closest_sum)
        results.append(min_difference)

    return results

