def determine_winner(N, A):
    left = 0
    right = N - 1
    last_added = -1
    turn = 0  # 0 for Alice, 1 for Bob

    while left <= right:
        if A[left] > last_added and A[right] > last_added:
            if A[left] < A[right]:
                last_added = A[left]
                left += 1
            else:
                last_added = A[right]
                right -= 1
        elif A[left] > last_added:
            last_added = A[left]
            left += 1
        elif A[right] > last_added:
            last_added = A[right]
            right -= 1
        else:
            break
        turn = 1 - turn

    if turn == 0:
        return "Bob"
    else:
        return "Alice"

